// ============================================================
// 時間範囲計算ノード
// Schedule / Webhook どちらから来ても統一した時間範囲を決定する
// ============================================================

const now = new Date();
let sinceDate;

// Webhookから来た場合（bodyにhours or sinceが入っている）
if ($input.first().json.body) {
  const body = $input.first().json.body;

  if (body.since) {
    // 特定日時以降を指定
    sinceDate = new Date(body.since);
  } else if (body.hours) {
    // N時間前から
    sinceDate = new Date(now.getTime() - body.hours * 60 * 60 * 1000);
  } else {
    // デフォルト: 2時間前
    sinceDate = new Date(now.getTime() - 2 * 60 * 60 * 1000);
  }
} else {
  // Scheduleから来た場合: 2時間前（実行間隔は最大6時間だが安全のため短めに）
  sinceDate = new Date(now.getTime() - 2 * 60 * 60 * 1000);
}

// Gmail API用のUnixタイムスタンプ（秒）
const sinceTimestamp = Math.floor(sinceDate.getTime() / 1000);

return [{
  json: {
    sinceTimestamp,
    sinceISO: sinceDate.toISOString(),
    nowISO: now.toISOString()
  }
}];

// ============================================================
// カテゴリ判定ノード
// メールを4カテゴリに分類してSlackチャンネルを決定する
// 
// 【カテゴリ追加方法】
// 下記のcategoriesに新しいオブジェクトをコピペで追加するだけ。
// ルール評価順は配列の順番通り。先にマッチしたカテゴリが適用される。
// ============================================================

const CATEGORIES = [
  {
    name: "報酬関係",
    slackChannel: "#gmail-報酬",
    rules: {
      // メールアドレスの一部でマッチ（部分一致、大文字小文字無視）
      from: [
        "payment@",
        "billing@",
        "invoice@",
        "payroll@"
      ],
      // 件名に含まれるキーワード（部分一致）
      subject: [
        "報酬",
        "給与",
        "支払い通知",
        "振込",
        "請求書",
        "インボイス"
      ],
      // 本文に含まれるキーワード（部分一致）
      keywords: [
        "振込",
        "入金",
        "支払い完了",
        "ご請求"
      ]
    }
  },
  {
    name: "IT情報",
    slackChannel: "#gmail-it",
    rules: {
      from: [
        "github.com",
        "github.io",
        "vercel.com",
        "cloudflare.com",
        "supabase.com",
        "netlify.com"
      ],
      subject: [
        "Pull Request",
        "[PR]",
        "Issue",
        "Deploy",
        "Merged",
        "Build",
        "Alert",
        "Security"
      ],
      keywords: [
        "Pull Request",
        "デプロイ",
        "障害",
        "セキュリティ"
      ]
    }
  },
  {
    name: "税務・行政",
    slackChannel: "#gmail-税務",
    rules: {
      from: [
        "e-tax",
        "nta.go.jp",
        "etax.nta.go.jp",
        "city.",
        "pref.",
        ".go.jp"
      ],
      subject: [
        "確定申告",
        "納税",
        "申告",
        "税務",
        "行政",
        "マイナンバー",
        "社会保険"
      ],
      keywords: [
        "国税",
        "地方税",
        "申告期限",
        "税務署",
        "役所"
      ]
    }
  },
  {
    // 上記カテゴリにマッチしなかったが重要そうなもの
    name: "その他重要",
    slackChannel: "#gmail-その他",
    rules: {
      from: [],
      subject: [
        "重要",
        "緊急",
        "【重要】",
        "【緊急】",
        "至急",
        "要対応",
        "要確認"
      ],
      keywords: [
        "至急",
        "対応必要",
        "期限",
        "締め切り"
      ]
    }
  }
];

// ---- 判定ロジック（通常変更不要） ----

function matchesAny(text, patterns) {
  if (!text || !patterns || patterns.length === 0) return false;
  const lowerText = text.toLowerCase();
  return patterns.some(p => lowerText.includes(p.toLowerCase()));
}

function classifyEmail(email) {
  const from    = email.from    || "";
  const subject = email.subject || "";
  const snippet = email.snippet || ""; // Gmailの本文プレビュー

  for (const cat of CATEGORIES) {
    const r = cat.rules;
    if (
      matchesAny(from, r.from) ||
      matchesAny(subject, r.subject) ||
      matchesAny(snippet, r.keywords)
    ) {
      return cat;
    }
  }
  return null; // どのカテゴリにも該当しない → スキップ
}

// ---- メール整形 ----

const results = [];

for (const item of $input.all()) {
  const email = item.json;
  const category = classifyEmail(email);

  if (!category) continue; // 重要でないメールは無視

  // 本文プレビュー（snippet）を整形
  const preview = (email.snippet || "").replace(/\s+/g, " ").substring(0, 200);

  // GmailへのURL
  const gmailUrl = `https://mail.google.com/mail/u/0/#inbox/${email.id}`;

  results.push({
    json: {
      category:      category.name,
      slackChannel:  category.slackChannel,
      from:          email.from    || "（送信者不明）",
      subject:       email.subject || "（件名なし）",
      preview,
      gmailUrl,
      messageId:     email.id,
      date:          email.date
    }
  });
}

return results;
